<# .SYNOPSIS Offline separation-of-duties regression for employee Agent collaboration. #>
param([switch]$PassThru)
$ErrorActionPreference='Stop';$root=(Resolve-Path(Join-Path $PSScriptRoot '..\..')).Path;$path=Join-Path $root '.qianlima\tmp\employee-agent-collaboration.json';New-Item -ItemType Directory -Path(Split-Path $path)-Force|Out-Null;$validator=Join-Path $PSScriptRoot 'validate-employee-agent-collaboration.ps1'
function P($role,$employee,$agent,$model,$provider,$error,$n){[ordered]@{role=$role;employee_id=$employee;agent_id=$agent;model_id=$model;model_version='v1';provider_family=$provider;error_group=$error;work_order_ref="work:$n";grant_ref="grant:$n"}}
function Run($mutator){$x=[ordered]@{collaboration_id='collab-test';task_id='task-test';fusion_id='fusion-test';risk_level='L3';participants=@((P manager emp-manager agent-manager model-manager local coordination 1),(P candidate emp-a agent-a model-a provider-a factual 2),(P candidate emp-b agent-b model-b provider-b causal 3),(P independent_verifier emp-v agent-v model-v provider-v verification 4),(P adversarial_checker emp-d agent-d model-d provider-d adversarial 5));manager_employee_id='emp-manager';final_adoption_authority='qianlima_broker';direct_agent_to_agent='deny';status='draft'};&$mutator $x;[IO.File]::WriteAllText($path,($x|ConvertTo-Json -Depth 10),[Text.UTF8Encoding]::new($false));$out=& powershell.exe -NoProfile -ExecutionPolicy Bypass -File $validator -ContractPath $path -PassThru 2>&1;[pscustomobject]@{code=$LASTEXITCODE;text=($out-join"`n")}}
$noop={param($x)};$self={param($x)$x.participants[3].employee_id='emp-a'};$sameError={param($x)$x.participants[2].error_group='factual'};$sameGrant={param($x)$x.participants[2].grant_ref='grant:2'};$direct={param($x)$x.direct_agent_to_agent='allow'};$cases=[System.Collections.Generic.List[object]]::new();$a=Run $noop;$b=Run $self;$c=Run $sameError;$d=Run $sameGrant;$e=Run $direct;$cases.Add([pscustomobject]@{name='valid_division_of_duties';passed=($a.code-eq0-and$a.text-match'validated')});$cases.Add([pscustomobject]@{name='employee_self_review_denied';passed=($b.code-ne0)});$cases.Add([pscustomobject]@{name='correlated_error_group_denied';passed=($c.code-ne0)});$cases.Add([pscustomobject]@{name='shared_grant_denied';passed=($d.code-ne0)});$cases.Add([pscustomobject]@{name='direct_agent_delegation_denied';passed=($e.code-ne0)});$failed=@($cases|?{-not$_.passed});$result=[pscustomobject]@{passed=($failed.Count-eq0);cases=@($cases);external_calls=$false;permissions_granted=$false};if($PassThru){$result|ConvertTo-Json -Depth 6}else{$cases|Format-Table -AutoSize};if($failed.Count){throw('Employee Agent collaboration regression failed: '+(($failed.name)-join', '))}
